(function (global) {
  'use strict';

  function splitCsvLine(line, delimiter) {
    var out = [];
    var current = '';
    var inQuotes = false;
    var i;
    var char;

    for (i = 0; i < line.length; i += 1) {
      char = line.charAt(i);

      if (char === '"') {
        if (inQuotes && line.charAt(i + 1) === '"') {
          current += '"';
          i += 1;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === delimiter && !inQuotes) {
        out.push(current);
        current = '';
      } else {
        current += char;
      }
    }

    out.push(current);
    return out;
  }

  function parseText(text, config) {
    var delimiter = config.delimiter || ',';
    var lines = text.split(/\r?\n/);
    var data = [];
    var errors = [];
    var headers = [];
    var i;
    var row;
    var rawHeaders;

    if (config.skipEmptyLines) {
      lines = lines.filter(function (line) {
        return String(line || '').trim().length > 0;
      });
    }

    if (!lines.length) {
      return { data: [], errors: [] };
    }

    if (config.header) {
      rawHeaders = splitCsvLine(lines[0], delimiter);
      headers = rawHeaders.map(function (header) {
        return typeof config.transformHeader === 'function' ? config.transformHeader(header) : header;
      });

      for (i = 1; i < lines.length; i += 1) {
        row = splitCsvLine(lines[i], delimiter);
        if (row.length === 1 && row[0] === '') {
          continue;
        }

        if (row.length > headers.length) {
          errors.push({ type: 'FieldMismatch', row: i + 1, message: 'Too many fields in row' });
        }

        data.push(headers.reduce(function (acc, key, colIndex) {
          acc[key] = row[colIndex] !== undefined ? row[colIndex] : '';
          return acc;
        }, {}));
      }
    } else {
      for (i = 0; i < lines.length; i += 1) {
        data.push(splitCsvLine(lines[i], delimiter));
      }
    }

    return { data: data, errors: errors };
  }

  function parse(input, config) {
    var cfg = config || {};

    function doneWithText(text) {
      var result = parseText(String(text || ''), cfg);
      if (typeof cfg.complete === 'function') {
        cfg.complete(result);
      }
    }

    if (typeof input === 'string') {
      doneWithText(input);
      return;
    }

    if (input && typeof FileReader !== 'undefined') {
      var reader = new FileReader();
      reader.onload = function () {
        doneWithText(reader.result);
      };
      reader.onerror = function (err) {
        if (typeof cfg.error === 'function') {
          cfg.error(err);
        }
      };
      reader.readAsText(input);
      return;
    }

    if (typeof cfg.error === 'function') {
      cfg.error(new Error('Unsupported input for Papa.parse'));
    }
  }

  global.Papa = {
    parse: parse
  };
})(window);
